import os
from flask import Flask, jsonify, request, send_file, abort

app = Flask(__name__)

# Base directory where user uploads are stored
BASE_UPLOAD_DIR = os.path.realpath(os.path.join(os.path.dirname(__file__), 'uploads'))


def get_safe_path(user_path):
    """
    Construct a safe absolute path from a user-provided relative path.
    Ensures the resolved path is within the BASE_UPLOAD_DIR to prevent
    path traversal attacks.
    """
    if user_path is None:
        return None, "Path parameter is required"

    # Normalize the user-provided path to collapse '..' and '.' components
    normalized = os.path.normpath(user_path)

    # Join with the base directory
    joined = os.path.join(BASE_UPLOAD_DIR, normalized)

    # Resolve to an absolute, canonical path (resolves symlinks too)
    real_path = os.path.realpath(joined)

    # Ensure the resolved path is strictly within the base upload directory
    # Use os.path.commonpath or check prefix with trailing separator
    base_with_sep = BASE_UPLOAD_DIR + os.sep
    if real_path != BASE_UPLOAD_DIR and not real_path.startswith(base_with_sep):
        return None, "Access denied: path is outside the allowed directory"

    return real_path, None


@app.route('/api/list', methods=['GET'])
def list_directory():
    """List contents of a directory relative to the user's upload root."""
    user_path = request.args.get('path', '.')

    safe_path, error = get_safe_path(user_path)
    if error:
        return jsonify({"error": error}), 400

    if not os.path.exists(safe_path):
        return jsonify({"error": "Directory not found"}), 404

    if not os.path.isdir(safe_path):
        return jsonify({"error": "Path is not a directory"}), 400

    entries = []
    try:
        for entry_name in sorted(os.listdir(safe_path)):
            entry_full_path = os.path.join(safe_path, entry_name)
            # Also verify each entry resolves within base dir (handles symlinks in listing)
            entry_real = os.path.realpath(entry_full_path)
            base_with_sep = BASE_UPLOAD_DIR + os.sep
            if entry_real != BASE_UPLOAD_DIR and not entry_real.startswith(base_with_sep):
                continue  # Skip entries that resolve outside the base directory (e.g., symlinks)

            stat_info = os.stat(entry_real)
            entry_type = "directory" if os.path.isdir(entry_real) else "file"
            entries.append({
                "name": entry_name,
                "type": entry_type,
                "size": stat_info.st_size if entry_type == "file" else None,
                "modified": stat_info.st_mtime
            })
    except PermissionError:
        return jsonify({"error": "Permission denied"}), 403

    # Compute the relative path for display
    relative_display = os.path.relpath(safe_path, BASE_UPLOAD_DIR)
    if relative_display == '.':
        relative_display = '/'

    return jsonify({
        "path": relative_display,
        "entries": entries,
        "count": len(entries)
    })


@app.route('/api/info', methods=['GET'])
def file_info():
    """Get detailed information about a file or directory."""
    user_path = request.args.get('path')
    if not user_path:
        return jsonify({"error": "Path parameter is required"}), 400

    safe_path, error = get_safe_path(user_path)
    if error:
        return jsonify({"error": error}), 400

    if not os.path.exists(safe_path):
        return jsonify({"error": "File or directory not found"}), 404

    try:
        stat_info = os.stat(safe_path)
    except PermissionError:
        return jsonify({"error": "Permission denied"}), 403

    is_dir = os.path.isdir(safe_path)
    relative_display = os.path.relpath(safe_path, BASE_UPLOAD_DIR)

    info = {
        "name": os.path.basename(safe_path),
        "path": relative_display,
        "type": "directory" if is_dir else "file",
        "size": stat_info.st_size,
        "modified": stat_info.st_mtime,
        "created": stat_info.st_ctime,
    }

    if not is_dir:
        info["extension"] = os.path.splitext(safe_path)[1].lstrip('.')

    if is_dir:
        try:
            contents = os.listdir(safe_path)
            info["num_entries"] = len(contents)
        except PermissionError:
            info["num_entries"] = None

    return jsonify(info)


@app.route('/api/download', methods=['GET'])
def download_file():
    """Download a file from the user's upload directory."""
    user_path = request.args.get('path')
    if not user_path:
        return jsonify({"error": "Path parameter is required"}), 400

    safe_path, error = get_safe_path(user_path)
    if error:
        return jsonify({"error": error}), 400

    if not os.path.exists(safe_path):
        return jsonify({"error": "File not found"}), 404

    if os.path.isdir(safe_path):
        return jsonify({"error": "Cannot download a directory. Use /api/list to browse."}), 400

    try:
        return send_file(
            safe_path,
            as_attachment=True,
            download_name=os.path.basename(safe_path)
        )
    except PermissionError:
        return jsonify({"error": "Permission denied"}), 403


@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Endpoint not found"}), 404


@app.errorhandler(500)
def internal_error(e):
    return jsonify({"error": "Internal server error"}), 500


if __name__ == '__main__':
    # Ensure the uploads directory exists
    os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)
    print(f"File explorer serving files from: {BASE_UPLOAD_DIR}")
    app.run(debug=False, host='127.0.0.1', port=5000)